mapper.select:
SELECT mr.request_id AS requestId, mr.mentee_id AS menteeId, e.employee_name AS menteeName, mr.mentoring_field AS mentoringField, mr.request_title AS requestTitle, mr.request_content AS requestContent, mr.request_status AS requestStatus, mr.created_at AS requestedAt FROM mentoring_request mr LEFT JOIN employee e ON mr.mentee_id = e.employee_id INNER JOIN employee_mentoring_field emf ON emf.employee_id = #{mentorId} AND emf.mentoring_field = mr.mentoring_field WHERE mr.request_status = 'PENDING' AND mr.mentee_id != #{mentorId} AND ( mr.rejected_mentor_ids IS NULL OR mr.rejected_mentor_ids = '[]' OR JSON_CONTAINS(mr.rejected_mentor_ids, CAST(#{mentorId} AS JSON)) = 0 )
AND mr.mentoring_field = #{mentoringField}
ORDER BY mr.created_at DESC
